import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip as ChartTooltip, Legend, ResponsiveContainer } from "recharts";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [filter, setFilter] = useState("All");
  const [showChart, setShowChart] = useState(false);

  // Fetch live bus data every 2 minutes
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://127.0.0.1:8000/buses");
        const data = await response.json();
        setBuses(data.buses || []);
      } catch (err) {
        console.error("Failed to fetch bus data:", err);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 2 * 60 * 1000); // every 2 minutes
    return () => clearInterval(interval);
  }, []);

  // Count statuses
  const runningCount = buses.filter((b) => b.status === "Running").length;
  const ghostCount = buses.filter((b) => b.status === "Ghost").length;
  const anomalyCount = buses.filter((b) => b.status === "Anomaly").length;

  // Filtered buses
  const filteredBuses =
    filter === "All"
      ? buses
      : buses.filter((b) => b.status === filter);

  // Prepare chart data (bus counts over time)
  const chartData = [
    { name: "Buses", Running: runningCount, Ghost: ghostCount, Anomaly: anomalyCount },
  ];

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Controls */}
      <div
        style={{
          position: "absolute",
          top: 12,
          left: 50,
          background: "rgba(255,255,255,0.95)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
          display: "flex",
          gap: "10px",
          alignItems: "center",
        }}
      >
        <label>
          Show:{" "}
          <select value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="All">All</option>
            <option value="Running">Running</option>
            <option value="Ghost">Ghost</option>
            <option value="Anomaly">Anomaly</option>
          </select>
        </label>
        <button onClick={() => setShowChart(!showChart)}>
          {showChart ? "Hide Chart" : "Show Chart"}
        </button>
      </div>

      {/* Bus counts */}
      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          background: "rgba(255,255,255,0.9)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        🟢 Running: {runningCount} <br />
        🔴 Ghost: {ghostCount} <br />
        🟠 Anomaly: {anomalyCount}
      </div>

      {/* Chart */}
      {showChart && (
        <div
          style={{
            position: "absolute",
            top: 60,
            left: 50,
            background: "rgba(255,255,255,0.95)",
            padding: "12px",
            borderRadius: "8px",
            boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
            zIndex: 1000,
            width: "400px",
            height: "250px",
          }}
        >
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis />
              <ChartTooltip />
              <Legend />
              <Line type="monotone" dataKey="Running" stroke="green" />
              <Line type="monotone" dataKey="Ghost" stroke="red" />
              <Line type="monotone" dataKey="Anomaly" stroke="orange" />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}

      {/* Map */}
      <MapContainer center={[40.7128, -74.006]} zoom={12} style={{ height: "100%", width: "100%" }}>
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {filteredBuses.map((bus) => (
          <CircleMarker
            key={`${bus.feed}-${bus.id}`} // fully stable
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={
              bus.status === "Running"
                ? "green"
                : bus.status === "Ghost"
                ? "red"
                : "orange"
            }
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Feed:</strong> {bus.feed} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong> {bus.speed ? bus.speed.toFixed(1) + " mph" : "N/A"}
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}
